// Gemini（gemini-3.1-flash-image）で1度だけ生成した汎用ラインアイコン集。
// フローチャートの各ステップは章ごとに内容が異なるため、生成のたびに
// AI画像を呼び出すのではなく、あらかじめ用意したこのアイコン群からステップの
// 文言に含まれるキーワードで最も近いものを選ぶ（scripts/tmp-gen-icons.ts参照、
// 再生成する場合は同スクリプトを使う）。
export const FLOW_ICONS: Record<string, string> = {
  check: "",
  gear: "",
  key: "",
  document: "",
  download: "",
  monitor: "",
  chat: "",
  flag: "",
};

const KEYWORD_MAP: [RegExp, string][] = [
  [/確認|検証|チェック|完了|テスト/, "check"],
  [/設定|環境|構築|調整|カスタマイズ|チューニング/, "gear"],
  [/認証|ログイン|キー|パスワード|アカウント|セキュ/, "key"],
  [/登録|入力|記入|作成|定義|規約|記載/, "document"],
  [/ダウンロード|インストール|取得|導入/, "download"],
  [/ダッシュボード|画面|モニタ|表示|閲覧/, "monitor"],
  [/報告|連絡|相談|対話|伝達|コミュニケーション|指示/, "chat"],
  [/開始|準備|起動|スタート|導入前/, "flag"],
];

// ステップの文言に含まれるキーワードから最も近いアイコンを選ぶ。
// マッチしない場合はundefinedを返し、呼び出し側はアイコンなしで表示する。
export function pickFlowIcon(stepText: string): string | undefined {
  for (const [pattern, key] of KEYWORD_MAP) {
    if (pattern.test(stepText)) return key;
  }
  return undefined;
}
